from fastapi import APIRouter, HTTPException
from typing import Any
import json

router = APIRouter(prefix="/api/click-chat", tags=["Click Chat"])
def _loads_embedded_json(raw: str) -> dict[str, dict[str, Any]]:
    escaped: list[str] = []
    in_string = False
    is_escaped = False

    for char in raw:
        if is_escaped:
            escaped.append(char)
            is_escaped = False
            continue
        if char == "\\":
            escaped.append(char)
            is_escaped = True
            continue
        if char == '"':
            in_string = not in_string
            escaped.append(char)
            continue
        if in_string and char in "\r\n\t":
            escaped.append(char.encode("unicode_escape").decode("ascii"))
            continue
        escaped.append(char)

    return json.loads("".join(escaped))

