def _screen(screen_id: str) -> dict[str, Any]:
    screen = CLICK_CHAT_SCREENS.get(screen_id)
    if not screen:
        raise HTTPException(status_code=404, detail=f"'{screen_id}' 화면을 찾을 수 없습니다.")
    return screen

@router.get("/start")
def start_click_chat() -> dict[str, Any]:
    return _screen("home")

@router.get("/home")
def get_click_chat_home() -> dict[str, Any]:
    return _screen("home")

@router.get("/screens")
def get_click_chat_screen_list() -> list[str]:
    return list(CLICK_CHAT_SCREENS.keys())

@router.get("/screens/{screen_id}")
def get_click_chat_screen(screen_id: str) -> dict[str, Any]:
    return _screen(screen_id)